{"query":"query getAccountTokenOwnerships($address: String!, $offset: Int, $limit: Int, $where: [current_token_ownerships_v2_bool_exp!]!, $order_by: [current_token_ownerships_v2_order_by!]!) {
  current_token_ownerships_v2(
    where: {owner_address: {_eq: $address}, amount: {_gt: 0}, current_token_data: {token_data_id: {_is_null: false}}, _and: $where}
    offset: $offset
    limit: $limit
    order_by: $order_by
  ) {
    ...TokenOwnershipFields
  }
}

fragment TokenOwnershipFields on current_token_ownerships_v2 {
  current_token_data {
    ...TokenDataFields
  }
  is_soulbound_v2
  owner_address
  amount
}

fragment TokenDataFields on current_token_datas_v2 {
  current_collection {
    ...CollectionDataFields
  }
  cdn_asset_uris {
    cdn_image_uri
  }
  last_transaction_timestamp
  last_transaction_version
  token_properties
  token_standard
  is_fungible_v2
  token_data_id
  description
  token_name
  token_uri
}

fragment CollectionDataFields on current_collections_v2 {
  uri
  max_supply
  description
  collection_name
  collection_id
  creator_address
  cdn_asset_uris {
    cdn_image_uri
  }
}","variables":{"address":"0xf26cbb3127abc72631e9236beacd595092126b5629ec53300e8ff1bb79f6cc5f","limit":10,"offset":0,"order_by":[{"last_transaction_timestamp":"desc"},{"last_transaction_version":"desc"}],"where":[]},"operationName":"getAccountTokenOwnerships"}

{"query":"query getAccountCollections($address: String!, $offset: Int, $limit: Int) {
  current_collection_ownership_v2_view(
    where: {owner_address: {_eq: $address}}
    offset: $offset
    limit: $limit
    order_by: [{last_transaction_version: desc}, {collection_id: desc}]
  ) {
    distinct_tokens
    single_token_uri
    current_collection {
      collection_id
      collection_name
      creator_address
      description
      uri
      cdn_asset_uris {
        cdn_image_uri
      }
    }
  }
}","variables":{"address":"0xf26cbb3127abc72631e9236beacd595092126b5629ec53300e8ff1bb79f6cc5f","limit":100,"offset":0},"operationName":"getAccountCollections"}

{"query":"
