{"query":"query getConsolidatedActivities($address: String!, $max_transaction_version: bigint, $limit: Int, $where: [account_transactions_bool_exp!], $fungible_asset_activities_where: [fungible_asset_activities_bool_exp!], $token_activities_v2_where: [token_activities_v2_bool_exp!]) {
  account_transactions(
    where: {account_address: {_eq: $address}, transaction_version: {_lt: $max_transaction_version}, _and: $where}
    limit: $limit
    order_by: {transaction_version: desc}
  ) {
    transaction_version
    fungible_asset_activities(where: {_and: $fungible_asset_activities_where}) {
      type
      amount
      owner_primary_aptos_name: owner_aptos_names(
        where: {is_primary: {_eq: true}, is_active: {_eq: true}}
      ) {
        domain
        subdomain
      }
      block_height
      asset_type
      metadata {
        decimals
        name
        symbol
        asset_type
      }
      entry_function_id_str
      owner_address
      event_index
      is_gas_fee
      gas_fee_payer_address
      is_transaction_success
      transaction_timestamp
      transaction_version
    }
    delegated_staking_activities(order_by: {event_index: desc}) {
      amount
      delegator_address
      event_index
      event_type
      pool_address
      transaction_version
    }
    token_activities_v2(where: {_and: $token_activities_v2_where}) {
      primary_aptos_name_from: aptos_names_from(
        where: {is_primary: {_eq: true}, is_active: {_eq: true}}
      ) {
        domain
        subdomain
      }
      primary_aptos_name_to: aptos_names_to(
        where: {is_primary: {_eq: true}, is_active: {_eq: true}}
      ) {
        domain
        subdomain
      }
      token_amount
      current_token_data {
        current_collection {
          collection_id
          collection_name
          creator_address
        }
        token_uri
        token_name
      }
      event_account_address
      event_index
      from_address
      property_version_v1
      to_address
      token_amount
      token_data_id
      transaction_timestamp
      transaction_version
      type
    }
    user_transaction {
      sequence_number
    }
  }
}","variables":{"address":"0xf26cbb3127abc72631e9236beacd595092126b5629ec53300e8ff1bb79f6cc5f","fungible_asset_activities_where":[],"limit":12,"max_transaction_version":"9223372036854775807","token_activities_v2_where":[],"where":[]},"operationName":"getConsolidatedActivities"}

